#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <cstring>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int* outputBuffer)
{
	int BLOCK_SIZE = omp_get_max_threads();
	int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

	int num_groups = (cols + small_block_cols - 1) / small_block_cols;

	#pragma omp parallel
	{
		int tx = omp_get_thread_num();
		int local_size = omp_get_num_threads();

		for (int bx = 0; bx < num_groups; bx++) {
			int blkX = (small_block_cols*bx) - border;
			int blkXmax = blkX + BLOCK_SIZE - 1;
			int xidx = blkX + tx;

			int validXmin = (blkX < 0) ? -blkX : 0;
			int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

			int W = tx - 1;
			int E = tx + 1;

			W = (W < validXmin) ? validXmin : W;
			E = (E > validXmax) ? validXmax : E;

			bool isValid = IN_RANGE(tx, validXmin, validXmax);

			int* prev = new int[BLOCK_SIZE];
			int* result = new int[BLOCK_SIZE];

			if (IN_RANGE(xidx, 0, cols - 1))
			{
				prev[tx] = gpuSrc[xidx];
			}
			else
			{
				prev[tx] = 0;
			}

			#pragma omp barrier

			bool computed = false;
			for (int i = 0; i < iteration; i++)
			{
				computed = false;

				if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid)
				{
					computed = true;
					int left = prev[W];
					int up = prev[tx];
					int right = prev[E];
					int shortest = MIN(left, up);
					shortest = MIN(shortest, right);

					int index = cols * (startStep + i) + xidx;
					result[tx] = shortest + gpuWall[index];

					if (tx == 11 && i == 0)
					{
						int bufIndex = gpuSrc[xidx];
						outputBuffer[bufIndex] = 1;
					}
				}

				#pragma omp barrier

				if (i == iteration - 1)
				{
					break;
				}

				if (computed)
				{
					prev[tx] = result[tx];
				}
				#pragma omp barrier
			}

			if (computed && IN_RANGE(xidx, 0, cols - 1))
			{
				gpuResults[xidx] = result[tx];
			}

			delete[] prev;
			delete[] result;
		}
	}
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;
	int size = rows * cols;

	int* d_gpuWall = data + cols; // wall excluding first row
	int* d_gpuResult[2];
	d_gpuResult[0] = data;
	d_gpuResult[1] = new int[cols];
	int* d_outputBuffer = new int[16384];
	memset(d_outputBuffer, 0, 16384 * sizeof(int));

	int src = 1, final_ret = 0;

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		dynproc_kernel(arg0,
		               d_gpuWall,
		               d_gpuResult[src],
		               d_gpuResult[final_ret],
		               cols,
		               rows,
		               t,
		               borderCols,
		               theHalo,
		               d_outputBuffer);
	}

	// Copy final results
	for (int i = 0; i < cols; i++) {
		result[i] = d_gpuResult[final_ret][i];
	}

	// Output buffer last char set to '\0' as in original code
	((char*)d_outputBuffer)[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] d_gpuResult[1];
	delete[] d_outputBuffer;
	delete[] data;
	delete[] wall;
	delete[] result;

	return EXIT_SUCCESS;
}
